const https = require('https');

const STORE = '7089d1-4e.myshopify.com';
const TOKEN = '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';

const query = \`{
  orders(first: 250, query: \"created_at:>=2026-04-01 created_at:<=2026-04-13\") {
    edges {
      node {
        createdAt
        totalPriceSet { shopMoney { amount } }
        lineItems(first: 20) {
          edges {
            node {
              title
              quantity
              originalTotalSet { shopMoney { amount } }
            }
          }
        }
      }
    }
  }
}\`;

const body = JSON.stringify({ query });
const options = {
  hostname: STORE,
  path: '/admin/api/2024-01/graphql.json',
  method: 'POST',
  headers: {
    'Content-Type': 'application/json',
    'X-Shopify-Access-Token': TOKEN,
    'Content-Length': Buffer.byteLength(body)
  }
};

const req = https.request(options, (res) => {
  let data = '';
  res.on('data', (chunk) => data += chunk);
  res.on('end', () => {
    try {
      const parsed = JSON.parse(data);
      const orders = parsed.data.orders.edges;
      console.log('Total orders in April:', orders.length);

      let totalRevenue = 0;
      const productMap = {};
      const dayMap = {};

      orders.forEach(({node: order}) => {
        const price = parseFloat(order.totalPriceSet.shopMoney.amount);
        totalRevenue += price;
        const day = order.createdAt.slice(0,10);
        dayMap[day] = (dayMap[day] || {count:0, revenue:0});
        dayMap[day].count++;
        dayMap[day].revenue += price;

        order.lineItems.edges.forEach(({node: item}) => {
          if (!productMap[item.title]) productMap[item.title] = {orders:0, qty:0, revenue:0};
          productMap[item.title].orders++;
          productMap[item.title].qty += item.quantity;
          productMap[item.title].revenue += parseFloat(item.originalTotalSet.shopMoney.amount);
        });
      });

      console.log('Total Revenue:', Math.round(totalRevenue));
      console.log('AOV:', Math.round(totalRevenue/orders.length));
      console.log('\\nDaily breakdown:');
      Object.entries(dayMap).sort().forEach(([d,v]) => {
        console.log(d + ': ' + v.count + '件 ¥' + Math.round(v.revenue));
      });
      console.log('\\nProduct breakdown:');
      Object.entries(productMap).sort((a,b)=>b[1].revenue-a[1].revenue).forEach(([p,v]) => {
        console.log(p + ': 注文' + v.orders + '回 数量' + v.qty + '個 売上¥' + Math.round(v.revenue));
      });
    } catch(e) {
      console.error('Parse error:', e.message);
      console.log('Raw:', data.slice(0,500));
    }
  });
});
req.on('error', (e) => console.error('Request error:', e.message));
